using namespace std;

bool isPalindrome(const string &s) {
    int left = 0;
    int right = s.size() - 1;
    while (left < right) {
        if (s[left] != s[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

long long solve(long long n, vector<vector<long long>> edges, string label) {
    unordered_map<long long, vector<long long>> graph;
    for (const auto &edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    long long max_len = 0;

    for (long long start = 0; start < n; ++start) {
        stack<tuple<long long, long long, string>> stk;
        stk.push({start, 1LL << start, string(1, label[start])});

        while (!stk.empty()) {
            auto [node, mask, current_str] = stk.top();
            stk.pop();

            if (isPalindrome(current_str)) {
                if (current_str.size() > max_len) {
                    max_len = current_str.size();
